import{_ as a,c as e,ao as s,o as n}from"./chunks/framework.DdZYLI3X.js";const h=JSON.parse('{"title":"Linux Debian下自定义守护进程的配置文件","description":"","frontmatter":{"title":"Linux Debian下自定义守护进程的配置文件","date":"2022-10-05T00:00:00.000Z","tags":"Linux"},"headers":[],"relativePath":"posts/Linux Debian下自定义守护进程的配置文件.md","filePath":"posts/Linux Debian下自定义守护进程的配置文件.md"}'),t={name:"posts/Linux Debian下自定义守护进程的配置文件.md"};function l(p,i,o,r,c,d){return n(),e("div",null,i[0]||(i[0]=[s(`<h1 id="文件位置" tabindex="-1">文件位置 <a class="header-anchor" href="#文件位置" aria-label="Permalink to &quot;文件位置&quot;">​</a></h1><p>systemd有系统和用户区分；系统（/user/lib/systemd/system/）、用户（/etc/lib/systemd/user/），一般系统管理员手工创建的单元文件存放在/etc/systemd/system/目录下面。</p><h1 id="部分配置文件的区块" tabindex="-1">部分配置文件的区块 <a class="header-anchor" href="#部分配置文件的区块" aria-label="Permalink to &quot;部分配置文件的区块&quot;">​</a></h1><h2 id="unit-区块" tabindex="-1">[Unit]区块 <a class="header-anchor" href="#unit-区块" aria-label="Permalink to &quot;[Unit]区块&quot;">​</a></h2><ul><li>Description：简短描述</li><li>Documentation：文档地址</li><li>Requires：当前 Unit 依赖的其他 Unit，如果它们没有运行，当前 Unit 会启动失败</li><li>Wants：与当前 Unit 配合的其他 Unit，如果它们没有运行，当前 Unit 不会启动失败</li><li>BindsTo：与Requires类似，它指定的 Unit 如果退出，会导致当前 Unit 停止运行</li><li>Before：如果该字段指定的 Unit 也要启动，那么必须在当前 Unit 之后启动</li><li>After：如果该字段指定的 Unit 也要启动，那么必须在当前 Unit 之前启动</li><li>Conflicts：这里指定的 Unit 不能与当前 Unit 同时运行</li><li>Condition...：当前 Unit 运行必须满足的条件，否则不会运行</li><li>Assert...：当前 Unit 运行必须满足的条件，否则会报启动失败</li></ul><h2 id="service-区块" tabindex="-1">[Service]区块 <a class="header-anchor" href="#service-区块" aria-label="Permalink to &quot;[Service]区块&quot;">​</a></h2><ul><li><p>Type：定义启动时的进程行为。它有以下几种值。</p><ul><li>simple：默认值，执行ExecStart指定的命令，启动主进程</li><li>forking：以 fork 方式从父进程创建子进程，创建后父进程会立即退出</li><li>oneshot：一次性进程，Systemd 会等当前服务退出，再继续往下执行</li><li>dbus：当前服务通过D-Bus启动</li><li>notify：当前服务启动完毕，会通知Systemd，再继续往下执行</li><li>idle：若有其他任务执行完毕，当前服务才会运行</li></ul></li><li><p>ExecStart：启动当前服务的命令</p></li><li><p>ExecStartPre：启动当前服务之前执行的命令</p></li><li><p>ExecStartPost：启动当前服务之后执行的命令</p></li><li><p>ExecReload：重启当前服务时执行的命令</p></li><li><p>ExecStop：停止当前服务时执行的命令</p></li><li><p>ExecStopPost：停止当其服务之后执行的命令</p></li><li><p>RestartSec：自动重启当前服务间隔的秒数</p></li><li><p>Restart：定义何种情况 Systemd 会自动重启当前服务，可能的值包括always（总是重启）、on-success、on-failure、on-abnormal、on-abort、on-watchdog</p></li><li><p>TimeoutSec：定义 Systemd 停止当前服务之前等待的秒数</p></li><li><p>Environment：指定环境变量</p></li></ul><h2 id="install-区块" tabindex="-1">[Install]区块 <a class="header-anchor" href="#install-区块" aria-label="Permalink to &quot;[Install]区块&quot;">​</a></h2><ul><li>Alias：为单元提供一个空间分离的附加名字。</li><li>RequiredBy：单元被允许运行需要的一系列依赖单元，RequiredBy列表从Require获得依赖信息。</li><li>WantBy：单元被允许运行需要的弱依赖性单元，Wantby从Want列表获得依赖信息。</li><li>Also：指出和单元一起安装或者被协助的单元。</li><li>DefaultInstance：实例单元的限制，这个选项指定如果单元被允许运行默认的实例。</li></ul><h1 id="配置文件示例" tabindex="-1">配置文件示例 <a class="header-anchor" href="#配置文件示例" aria-label="Permalink to &quot;配置文件示例&quot;">​</a></h1><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;" tabindex="0"><code><span class="line"><span>[Unit]</span></span>
<span class="line"><span>Description=Brook Service # 描述</span></span>
<span class="line"><span>Documentation=https://txthinking.github.io/brook/ # 文档链接</span></span>
<span class="line"><span>After=network.target nss-lookup.target # 启动的前置为网络服务</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[Service]</span></span>
<span class="line"><span>User=root # 用户</span></span>
<span class="line"><span>Type=simple # 默认值，执行ExecStart指定的命令，启动主进程</span></span>
<span class="line"><span>CapabilityBoundingSet=CAP_NET_ADMIN CAP_NET_RAW # 允许执行网络管理任务和原始套接字</span></span>
<span class="line"><span>AmbientCapabilities=CAP_NET_ADMIN CAP_NET_RAW # 允许执行网络管理任务和原始套接字</span></span>
<span class="line"><span>NoNewPrivileges=true # 该服务的所有进程与子进程都不可以获得任何新权限。</span></span>
<span class="line"><span>ExecStart=brook server --listen :8888 --password 123456 # 启动当前服务的命令</span></span></code></pre></div>`,11)]))}const _=a(t,[["render",l]]);export{h as __pageData,_ as default};
